import React, { useState } from 'react';

const AIAssist = () => {
    const [query, setQuery] = useState('');
    const [chat, setChat] = useState([
        { sender: 'ai', text: 'Hello! I am your AI-NOC assistant. How can I help you analyze the network today?' }
    ]);

    const handleSend = (e) => {
        e.preventDefault();
        if (!query.trim()) return;
        
        // Add user message and a simulated AI response
        setChat([...chat, 
            { sender: 'user', text: query }, 
            { sender: 'ai', text: 'Analyzing current telemetry... All core systems are currently stable, though I noticed recent impedance mismatches on the APs. Would you like me to run a diagnostic?' }
        ]);
        setQuery('');
    };

    return (
        <div style={{ marginTop: '2rem', backgroundColor: '#1f2937', padding: '2rem', borderRadius: '0.5rem' }}>
            <h2 style={{ fontSize: '1.5rem', color: '#f3f4f6', margin: '0 0 1.5rem 0' }}>Network AI Assistant</h2>
            
            <div style={{ height: '400px', overflowY: 'auto', marginBottom: '1rem', padding: '1rem', backgroundColor: '#111827', borderRadius: '0.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {chat.map((msg, idx) => (
                    <div key={idx} style={{ alignSelf: msg.sender === 'user' ? 'flex-end' : 'flex-start', maxWidth: '80%' }}>
                        <div style={{ fontSize: '0.75rem', color: '#9ca3af', marginBottom: '0.25rem', textAlign: msg.sender === 'user' ? 'right' : 'left' }}>
                            {msg.sender === 'user' ? 'You' : 'AI Assistant'}
                        </div>
                        <div style={{
                            padding: '0.75rem 1rem',
                            borderRadius: '0.5rem',
                            backgroundColor: msg.sender === 'user' ? '#3b82f6' : '#374151',
                            color: '#f3f4f6',
                            lineHeight: '1.5'
                        }}>
                            {msg.text}
                        </div>
                    </div>
                ))}
            </div>

            <form onSubmit={handleSend} style={{ display: 'flex', gap: '1rem' }}>
                <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Ask about network health or anomalies..."
                    style={{ flex: 1, padding: '0.75rem 1rem', borderRadius: '0.5rem', border: '1px solid #4b5563', backgroundColor: '#374151', color: '#f3f4f6', outline: 'none' }}
                />
                <button type="submit" style={{ padding: '0.75rem 1.5rem', borderRadius: '0.5rem', border: 'none', backgroundColor: '#10b981', color: 'white', fontWeight: 'bold', cursor: 'pointer', transition: 'background-color 0.2s' }}>
                    Send
                </button>
            </form>
        </div>
    );
};

export default AIAssist;
